parameters.jsCode:
const items = $input.all();
const chatId = $('Telegram Trigger').first().json.message?.chat?.id 
  || $('Telegram Trigger').first().json.callback_query?.message?.chat?.id;
const tickets = items.filter(item => item.json.ticket_id);
const hasTickets = tickets.length > 0;

if (!hasTickets) {
  return [{
    json: {
      chat_id: chatId,
      text: "📋 No open tickets found. Please describe your issue first and we'll create a ticket for you.",
      reply_markup: JSON.stringify({ inline_keyboard: [] }),
      hasTickets: false
    }
  }];
}

const buttons = tickets.map(item => ([{
  text: `${item.json.ticket_id} - ${item.json.keywords}`,
  callback_data: `m||${item.json.ticket_id}`
}]));

buttons.push([{
  text: "Don't Upload",
  callback_data: "m||ignore"
}]);

return [{
  json: {
    chat_id: chatId,
    text: "Which ticket is this photo for?",
    reply_markup: JSON.stringify({ inline_keyboard: buttons }),
    hasTickets: true
  }
}];

